import { ComboChart } from '@carbon/charts-react';

const data = [
  { group: 'Sales', key: 'Q1', value: 34200 },
  { group: 'Sales', key: 'Q2', value: 29800 },
  { group: 'Growth', key: 'Q1', value: 20 },
  { group: 'Growth', key: 'Q2', value: 35 },
];
const options = {
  title: 'Combo (bar + line)',
  theme: 'white',
  height: '400px',
  axes: {
    left: { mapsTo: 'value' },
    bottom: { mapsTo: 'key', scaleType: 'labels' },
    right: { mapsTo: 'value', correspondingDatasets: ['Growth'] },
  },
  comboChartTypes: [
    { type: 'stacked-bar', correspondingDatasets: ['Sales'] },
    { type: 'line', correspondingDatasets: ['Growth'] },
  ],
};

export const Demo = () => <ComboChart data={data} options={options} />;

